patch:
diff --git a/llvm/lib/Analysis/ScalarEvolution.cpp b/llvm/lib/Analysis/ScalarEvolution.cpp
index c3f296b9ff33..faaab357f3cc 100644
--- a/llvm/lib/Analysis/ScalarEvolution.cpp
+++ b/llvm/lib/Analysis/ScalarEvolution.cpp
@@ -2529,7 +2529,12 @@ StrengthenNoWrapFlags(ScalarEvolution *SE, SCEVTypes Type,
 }

 bool ScalarEvolution::isAvailableAtLoopEntry(const SCEV *S, const Loop *L) {
-  return isLoopInvariant(S, L) && properlyDominates(S, L->getHeader());
+  // For the purposes of forming valid AddRecExprs and reasoning about SCEVs,
+  // loop-invariance is the essential requirement. Some SCEV expressions (e.g.,
+  // addrecs from outer loops) are valid operands for inner-loop recurrences
+  // even if their underlying IR does not strictly dominate the loop header.
+  // Treat loop-invariant expressions as available at loop entry.
+  return isLoopInvariant(S, L);
 }

 /// Get a canonical add expression, or something simpler if possible.

